from typing import List, Dict, Any, Tuple, Optional
from datetime import datetime
import uuid

from .models import (
    MainRecord, SupplementRecord, ValidationRule,
    ValidationResult, RecordStatus, AbnormalType, AbnormalDetail,
    HistoryEntry, OutputBundle
)


class ValidationEngine:
    """校验引擎"""

    def __init__(self, rules: List[ValidationRule], operator: str = "system"):
        self.rules = rules
        self.operator = operator
        self.admission_rules = [r for r in rules if r.rule_type == "admission"]
        self.threshold_rules = [r for r in rules if r.rule_type == "threshold"]
        self.material_rules = [r for r in rules if r.rule_type == "material"]
        self.consistency_rules = [r for r in rules if r.rule_type == "consistency"]

    def validate(
        self,
        main_records: List[MainRecord],
        supplement_records: List[SupplementRecord],
        existing_history: Optional[List[Dict[str, Any]]] = None,
        strict_mode: bool = False
    ) -> OutputBundle:
        """执行完整校验流程"""
        batch_id = self._generate_batch_id()
        generated_at = datetime.now().isoformat()

        supplement_map = {s.record_id: s for s in supplement_records}

        normal: List[ValidationResult] = []
        abnormal: List[ValidationResult] = []
        pending: List[ValidationResult] = []
        history_entries: List[HistoryEntry] = []

        existing_history_map = self._build_history_map(existing_history or [])

        for main_record in main_records:
            supplement = supplement_map.get(main_record.record_id)
            result = self._validate_single(main_record, supplement, strict_mode)

            previous_status = existing_history_map.get(main_record.record_id)

            if previous_status and previous_status != result.status:
                history_entry = HistoryEntry(
                    timestamp=generated_at,
                    batch_id=batch_id,
                    record_id=main_record.record_id,
                    previous_status=previous_status,
                    new_status=result.status,
                    operator=self.operator,
                    reason=self._generate_status_change_reason(previous_status, result.status, result),
                    abnormal_details=result.abnormal_details.copy()
                )
                history_entries.append(history_entry)
            elif not previous_status:
                history_entry = HistoryEntry(
                    timestamp=generated_at,
                    batch_id=batch_id,
                    record_id=main_record.record_id,
                    previous_status=RecordStatus.PENDING_REVIEW,
                    new_status=result.status,
                    operator=self.operator,
                    reason=f"首次校验，状态判定为{result.status}",
                    abnormal_details=result.abnormal_details.copy()
                )
                history_entries.append(history_entry)

            if result.status == RecordStatus.NORMAL:
                normal.append(result)
            elif result.status == RecordStatus.ABNORMAL:
                abnormal.append(result)
            else:
                pending.append(result)

        return OutputBundle(
            normal_records=normal,
            abnormal_records=abnormal,
            pending_records=pending,
            history_entries=history_entries,
            batch_id=batch_id,
            generated_at=generated_at
        )

    def _validate_single(
        self,
        main_record: MainRecord,
        supplement: Optional[SupplementRecord],
        strict_mode: bool
    ) -> ValidationResult:
        """校验单条记录"""
        abnormal_details: List[AbnormalDetail] = []

        abnormal_details.extend(self._check_admission(main_record, supplement))
        if abnormal_details and strict_mode:
            return self._create_result(main_record, supplement, abnormal_details, RecordStatus.ABNORMAL)

        abnormal_details.extend(self._check_material(main_record, supplement))
        abnormal_details.extend(self._check_threshold(main_record, supplement))
        abnormal_details.extend(self._check_consistency(main_record, supplement))

        if not abnormal_details:
            status = RecordStatus.NORMAL
        elif any(d.abnormal_type == AbnormalType.ADMISSION_DENIED for d in abnormal_details):
            status = RecordStatus.ABNORMAL
        elif any(d.abnormal_type == AbnormalType.MATERIAL_MISSING for d in abnormal_details):
            status = RecordStatus.ABNORMAL
        elif strict_mode:
            status = RecordStatus.ABNORMAL
        else:
            status = RecordStatus.PENDING_REVIEW

        return self._create_result(main_record, supplement, abnormal_details, status)

    def _check_admission(
        self,
        main_record: MainRecord,
        supplement: Optional[SupplementRecord]
    ) -> List[AbnormalDetail]:
        """准入判断"""
        details: List[AbnormalDetail] = []

        for rule in self.admission_rules:
            value = self._get_field_value(main_record, supplement, rule.field)
            if not self._evaluate_rule(value, rule.operator, rule.threshold):
                detail = AbnormalDetail(
                    abnormal_type=AbnormalType.ADMISSION_DENIED,
                    field=rule.field,
                    expected=self._format_expected(rule),
                    actual=value,
                    reason=f"准入不通过: {rule.description or rule.rule_name}",
                    source_line=main_record.source_line,
                    rule_id=rule.rule_id
                )
                details.append(detail)

        return details

    def _check_material(
        self,
        main_record: MainRecord,
        supplement: Optional[SupplementRecord]
    ) -> List[AbnormalDetail]:
        """材料完整性检查"""
        details: List[AbnormalDetail] = []

        for rule in self.material_rules:
            missing_fields = []
            for field in rule.required_fields:
                value = self._get_field_value(main_record, supplement, field)
                if value is None or (isinstance(value, str) and not value.strip()):
                    missing_fields.append(field)

            if missing_fields:
                detail = AbnormalDetail(
                    abnormal_type=AbnormalType.MATERIAL_MISSING,
                    field=rule.field,
                    expected=f"必填字段: {', '.join(rule.required_fields)}",
                    actual=f"缺失字段: {', '.join(missing_fields)}",
                    reason=f"材料缺失: {rule.description or rule.rule_name}",
                    source_line=main_record.source_line,
                    rule_id=rule.rule_id
                )
                details.append(detail)

        return details

    def _check_threshold(
        self,
        main_record: MainRecord,
        supplement: Optional[SupplementRecord]
    ) -> List[AbnormalDetail]:
        """阈值检查"""
        details: List[AbnormalDetail] = []

        for rule in self.threshold_rules:
            value = self._get_field_value(main_record, supplement, rule.field)
            if value is not None and not self._evaluate_rule(value, rule.operator, rule.threshold):
                detail = AbnormalDetail(
                    abnormal_type=AbnormalType.THRESHOLD_EXCEEDED,
                    field=rule.field,
                    expected=self._format_expected(rule),
                    actual=value,
                    reason=f"超阈值: {rule.description or rule.rule_name}",
                    source_line=main_record.source_line,
                    rule_id=rule.rule_id
                )
                details.append(detail)

        return details

    def _check_consistency(
        self,
        main_record: MainRecord,
        supplement: Optional[SupplementRecord]
    ) -> List[AbnormalDetail]:
        """数据一致性检查"""
        details: List[AbnormalDetail] = []

        if supplement is None:
            return details

        for rule in self.consistency_rules:
            if len(rule.related_fields) >= 2:
                values = []
                for field in rule.related_fields:
                    val = self._get_field_value(main_record, supplement, field)
                    values.append((field, val))

                main_val = self._get_field_value(main_record, supplement, rule.related_fields[0])
                for field, val in values[1:]:
                    if str(main_val).strip() != str(val).strip():
                        detail = AbnormalDetail(
                            abnormal_type=AbnormalType.DATA_INCONSISTENCY,
                            field=rule.field,
                            expected=f"{rule.related_fields[0]}={main_val}",
                            actual=f"{field}={val}",
                            reason=f"数据不一致: {rule.description or rule.rule_name}",
                            source_line=main_record.source_line,
                            rule_id=rule.rule_id
                        )
                        details.append(detail)
                        break

        return details

    @staticmethod
    def _get_field_value(
        main_record: MainRecord,
        supplement: Optional[SupplementRecord],
        field: str
    ) -> Any:
        """获取字段值"""
        if hasattr(main_record, field):
            return getattr(main_record, field)
        if supplement and hasattr(supplement, field):
            return getattr(supplement, field)
        if field in main_record.raw_data:
            return main_record.raw_data[field]
        if supplement and field in supplement.raw_data:
            return supplement.raw_data[field]
        return None

    @staticmethod
    def _evaluate_rule(value: Any, operator: str, threshold: Any) -> bool:
        """评估规则"""
        if value is None:
            return False

        try:
            if operator in (">", "<", ">=", "<=", "==", "!="):
                if isinstance(value, str) and value.replace('.', '').isdigit():
                    value = float(value) if '.' in value else int(value)
                if isinstance(threshold, str) and threshold.replace('.', '').isdigit():
                    threshold = float(threshold) if '.' in threshold else int(threshold)

            if operator == ">":
                return value > threshold
            elif operator == "<":
                return value < threshold
            elif operator == ">=":
                return value >= threshold
            elif operator == "<=":
                return value <= threshold
            elif operator == "==":
                return str(value).strip() == str(threshold).strip()
            elif operator == "!=":
                return str(value).strip() != str(threshold).strip()
            elif operator == "in":
                if isinstance(threshold, list):
                    return str(value).strip() in [str(t).strip() for t in threshold]
                return str(value).strip() in str(threshold).split('|')
            elif operator == "not_in":
                if isinstance(threshold, list):
                    return str(value).strip() not in [str(t).strip() for t in threshold]
                return str(value).strip() not in str(threshold).split('|')
            elif operator == "contains":
                return str(threshold).lower() in str(value).lower()
            elif operator == "not_contains":
                return str(threshold).lower() not in str(value).lower()
            elif operator == "length_ge":
                return len(str(value).strip()) >= int(threshold)
            elif operator == "length_le":
                return len(str(value).strip()) <= int(threshold)
        except (TypeError, ValueError):
            return False

        return True

    @staticmethod
    def _format_expected(rule: ValidationRule) -> str:
        """格式化期望值"""
        if isinstance(rule.threshold, list):
            threshold_str = ', '.join(map(str, rule.threshold))
        else:
            threshold_str = str(rule.threshold)

        operator_map = {
            ">": "大于",
            "<": "小于",
            ">=": "大于等于",
            "<=": "小于等于",
            "==": "等于",
            "!=": "不等于",
            "in": "在范围内",
            "not_in": "不在范围内",
            "contains": "包含",
            "not_contains": "不包含",
            "length_ge": "长度大于等于",
            "length_le": "长度小于等于"
        }

        op_name = operator_map.get(rule.operator, rule.operator)
        return f"{op_name} {threshold_str}"

    @staticmethod
    def _create_result(
        main_record: MainRecord,
        supplement: Optional[SupplementRecord],
        abnormal_details: List[AbnormalDetail],
        status: RecordStatus
    ) -> ValidationResult:
        """创建校验结果"""
        notes = ""
        if abnormal_details:
            reasons = [d.reason for d in abnormal_details]
            notes = "; ".join(reasons)

        return ValidationResult(
            record_id=main_record.record_id,
            status=status,
            main_record=main_record,
            supplement_record=supplement,
            abnormal_details=abnormal_details,
            review_notes=notes
        )

    @staticmethod
    def _generate_batch_id() -> str:
        """生成批次ID"""
        return f"BATCH-{datetime.now().strftime('%Y%m%d-%H%M%S')}-{uuid.uuid4().hex[:6].upper()}"

    @staticmethod
    def _build_history_map(history: List[Dict[str, Any]]) -> Dict[str, RecordStatus]:
        """构建历史状态映射"""
        status_map: Dict[str, RecordStatus] = {}
        for entry in history:
            record_id = entry.get('record_id')
            new_status = entry.get('new_status')
            if record_id and new_status:
                try:
                    status_map[record_id] = RecordStatus(new_status)
                except ValueError:
                    pass
        return status_map

    @staticmethod
    def _generate_status_change_reason(
        previous: RecordStatus,
        current: RecordStatus,
        result: ValidationResult
    ) -> str:
        """生成状态变更原因"""
        if result.abnormal_details:
            reasons = [d.reason for d in result.abnormal_details]
            return f"状态由{previous}变更为{current}，原因: {'; '.join(reasons)}"
        return f"状态由{previous}变更为{current}"
